import { call, put, takeEvery } from 'redux-saga/effects';
import {
  SET_USER_AVATAR_ASYNC,
  SET_USER_AVATAR_FAILED,
  SET_USER_AVATAR_PROGRESS,
  SET_USER_AVATAR_SUCCESS,
  SET_USER_PROFILE_ASYNC,
  SET_USER_PROFILE_FAILED,
  SET_USER_PROFILE_PROGRESS,
  SET_USER_PROFILE_SUCCESS,
  DELETE_ACCOUNT_ASYNC,
  DELETE_ACCOUNT_FAILED,
  DELETE_ACCOUNT_PROGRESS,
  DELETE_ACCOUNT_SUCCESS,
} from './contains';
import { userUpdatePayload } from './types';
import { store } from '../../store';
import { fetchDeleteAccount, fetchUpdateUserProfile } from '../../../api/user';
import { ResponseApi } from '../../store/types';
import { updateUserProfile } from '../auth/actions';
import {
  HIDE_LOADING_OVERLAY,
  SHOW_ALERT,
  SHOW_LOADING_OVERLAY,
} from '../app/constants';
import { logout } from '../auth/actions';
import i18n from '../../../i18n';

const handleUpdateAvatar = function* (action: {
  type: string;
  payload: userUpdatePayload;
}): Generator<any, void, any> {
  try {
    yield put({ type: SET_USER_AVATAR_PROGRESS, payload: true });
    const profile = store.getState().auth.userProfile;

    const accountId = profile?.accountId;
    if (!accountId) return;

    const payload = {
      PhotoImage: action.payload.PhotoImage || null,
    };

    const response = (yield call(
      fetchUpdateUserProfile,
      accountId,
      payload,
    )) as ResponseApi;
    if (response.status !== 200) {
      yield put({ type: SET_USER_AVATAR_FAILED, payload: response.message });
      return;
    }
    yield put(updateUserProfile({ photoUrl: action.payload.PhotoImage?.uri }));
    yield put({ type: SET_USER_AVATAR_SUCCESS, payload: response.data });
  } catch (error) {
    yield put({ type: SET_USER_AVATAR_FAILED, payload: error });
  } finally {
    yield put({ type: SET_USER_AVATAR_PROGRESS, payload: false });
  }
};

export const handleUpdateUserProfile = function* (action: {
  type: string;
  payload: userUpdatePayload;
}): Generator<any, void, any> {
  try {
    yield put({ type: SHOW_LOADING_OVERLAY });
    yield put({ type: SET_USER_PROFILE_PROGRESS, payload: true });
    const profile = store.getState().auth.userProfile;

    const accountId = profile?.accountId;
    if (!accountId) return;

    const payload = {
      FirstName: action.payload.FirstName
        ? action.payload.FirstName.trim()
        : profile?.firstName,
      LastName: action.payload.LastName
        ? action.payload.LastName.trim()
        : profile?.lastName,
      SSNOrITIN: action.payload.SSNOrITIN
        ? action.payload.SSNOrITIN.trim()
        : profile?.ssnOrITIN,
    };

    const response = (yield call(
      fetchUpdateUserProfile,
      accountId,
      payload,
    )) as ResponseApi;
    if (response.status !== 200) {
      yield put({ type: SET_USER_AVATAR_FAILED, payload: response.message });
      return;
    }
    yield put(
      updateUserProfile({
        firstName: payload.FirstName ? payload.FirstName : profile?.firstName,
        lastName: payload.LastName ? payload.LastName : profile?.lastName,
        ssnOrITIN: payload.SSNOrITIN ? payload.SSNOrITIN : profile?.ssnOrITIN,
      }),
    );
    yield put({ type: SET_USER_PROFILE_SUCCESS, payload: response.data });
  } catch (error) {
    yield put({ type: SET_USER_PROFILE_FAILED, payload: error });
  } finally {
    yield put({ type: SET_USER_PROFILE_PROGRESS, payload: false });
    yield put({ type: HIDE_LOADING_OVERLAY });
  }
};

const handleDeleteAccount = function* (): Generator<any, void, any> {
  try {
    yield put({ type: SHOW_LOADING_OVERLAY });
    yield put({ type: DELETE_ACCOUNT_PROGRESS, payload: true });
    const profile = store.getState().auth.userProfile;

    const accountId = profile?.accountId;
    if (!accountId) return;

    const response = (yield call(fetchDeleteAccount, accountId)) as ResponseApi;

    if (response.status !== 200) {
      yield put({
        type: SHOW_ALERT,
        payload: {
          title: i18n.t('ERROR'),
          message: response.message,
          type: 'error',
        },
      });
      yield put({ type: DELETE_ACCOUNT_FAILED, payload: response.message });
      return;
    }

    yield put({ type: DELETE_ACCOUNT_SUCCESS, payload: response.data });
    yield put(logout());
  } catch (error) {
    yield put({ type: DELETE_ACCOUNT_FAILED, payload: error });
  } finally {
    yield put({ type: DELETE_ACCOUNT_PROGRESS, payload: false });
    yield put({ type: HIDE_LOADING_OVERLAY });
  }
};

export default function* userSaga(): Generator<any, void, any> {
  yield takeEvery(SET_USER_AVATAR_ASYNC, handleUpdateAvatar);
  yield takeEvery(SET_USER_PROFILE_ASYNC, handleUpdateUserProfile);
  yield takeEvery(DELETE_ACCOUNT_ASYNC, handleDeleteAccount);
}
