import { logger } from '../utils';
import { client } from './configAxios';
import { getReferralDetailJob, referaFriend } from './endpoint';

export const fetchReferFriend = async () => {
  try {
    const response = await client.get(referaFriend);
    return {
      status: response.data.statusCode,
      code: response.data.code,
      data: response.data.data,
    };
  } catch (error: any) {
    logger('error fetchReferFriend', error);
    return {
      message: error?.response?.data?.message,
      code: error?.code,
      status: error?.status,
    };
  }
};

export const fetchReferFriendDetail = async (referralId: string) => {
  try {
    const response = await client.get(
      `${getReferralDetailJob}?referralId=${referralId}`,
    );
    return {
      status: response.data.statusCode,
      code: response.data.code,
      data: response.data.data,
    };
  } catch (error: any) {
    logger('error fetchReferFriendDetail', error);
    return {
      message: error?.response?.data?.message,
      code: error?.code,
      status: error?.status,
    };
  }
};
