import {
  GET_MY_JOBS_ASYNC,
  GET_MY_JOBS_SUCCESS,
  GET_MY_JOBS_FAILED,
  GET_MY_JOBS_PROGRESS,
  GET_COMMUNITIES_ASYNC,
  GET_COMMUNITIES_SUCCESS,
  GET_COMMUNITIES_FAILED,
  GET_COMMUNITIES_PROGRESS,
  SET_MY_JOB_FILTER_PARAMS,
  RESET_MY_JOB_STATE,
  GET_GANTT_DATA_ASYNC,
  GET_GANTT_DATA_SUCCESS,
  GET_GANTT_DATA_FAILED,
  GET_GANTT_DATA_PROGRESS,
  GET_MY_JOBS_WARRANTY_ASYNC,
  GET_MY_JOBS_WARRANTY_FAILED,
  GET_MY_JOBS_WARRANTY_SUCCESS,
  GET_MY_JOBS_WARRANTY_PROGRESS,
  SUBMIT_WARRANTY_ASYNC,
  SUBMIT_WARRANTY_SUCCESS,
  SUBMIT_WARRANTY_FAILED,
  SUBMIT_WARRANTY_PROGRESS,
  GET_MATERIALS_WARRANTY_ASYNC,
  GET_MATERIALS_WARRANTY_SUCCESS,
  GET_MATERIALS_WARRANTY_FAILED,
  GET_MATERIALS_WARRANTY_PROGRESS,
  UPDATE_MATERIAL_WARRANTY_ITEM,
  CLEAR_WARRANTY_DATA,
} from './contants';
import { JobItem, MyJobsFilterParams } from './types';

// action saga
export const getMyJobsAsync = (params: any) =>
  ({ type: GET_MY_JOBS_ASYNC, payload: params } as const);

export const getCommunitiesAsync = () =>
  ({ type: GET_COMMUNITIES_ASYNC } as const);

// action reducer

export const getMyJobsSuccess = (payload: JobItem[]) =>
  ({ type: GET_MY_JOBS_SUCCESS, payload } as const);

export const getMyJobsFailed = (payload: any) =>
  ({ type: GET_MY_JOBS_FAILED, payload } as const);

export const getMyJobsProgress = (payload: boolean) =>
  ({ type: GET_MY_JOBS_PROGRESS, payload } as const);

export const getCommunitiesSuccess = (payload: any) =>
  ({ type: GET_COMMUNITIES_SUCCESS, payload } as const);

export const getCommunitiesFailed = (payload: any) =>
  ({ type: GET_COMMUNITIES_FAILED, payload } as const);

export const getCommunitiesProgress = (payload: boolean) =>
  ({ type: GET_COMMUNITIES_PROGRESS, payload } as const);

export const setMyJobFilterParams = (payload: MyJobsFilterParams) =>
  ({ type: SET_MY_JOB_FILTER_PARAMS, payload } as const);

export const resetMyJobState = () => ({ type: RESET_MY_JOB_STATE } as const);

export const getGanttDataAsync = (payload: any) =>
  ({ type: GET_GANTT_DATA_ASYNC, payload } as const);

export const getGanttDataSuccess = (payload: any) =>
  ({ type: GET_GANTT_DATA_SUCCESS, payload } as const);

export const getGanttDataFailed = (payload: any) =>
  ({ type: GET_GANTT_DATA_FAILED, payload } as const);

export const getGanttDataProgress = (payload: boolean) =>
  ({ type: GET_GANTT_DATA_PROGRESS, payload } as const);

export const getMyJobsWarrantyAsync = (payload: any) =>
  ({ type: GET_MY_JOBS_WARRANTY_ASYNC, payload } as const);

export const getMyJobsWarrantySuccess = (payload: any) =>
  ({ type: GET_MY_JOBS_WARRANTY_SUCCESS, payload } as const);

export const getMyJobsWarrantyFailed = (payload: any) =>
  ({ type: GET_MY_JOBS_WARRANTY_FAILED, payload } as const);

export const getMyJobsWarrantyProgress = (payload: boolean) =>
  ({ type: GET_MY_JOBS_WARRANTY_PROGRESS, payload } as const);

export const submitWarrantyAsync = (payload: any) =>
  ({ type: SUBMIT_WARRANTY_ASYNC, payload } as const);

export const submitWarrantySuccess = (payload: any) =>
  ({ type: SUBMIT_WARRANTY_SUCCESS, payload } as const);

export const submitWarrantyFailed = (payload: any) =>
  ({ type: SUBMIT_WARRANTY_FAILED, payload } as const);

export const submitWarrantyProgress = (payload: boolean) =>
  ({ type: SUBMIT_WARRANTY_PROGRESS, payload } as const);

export const getMaterialsWarrantyAsync = (payload: any) =>
  ({ type: GET_MATERIALS_WARRANTY_ASYNC, payload } as const);

export const getMaterialsWarrantySuccess = (payload: any) =>
  ({ type: GET_MATERIALS_WARRANTY_SUCCESS, payload } as const);

export const getMaterialsWarrantyFailed = (payload: any) =>
  ({ type: GET_MATERIALS_WARRANTY_FAILED, payload } as const);

export const getMaterialsWarrantyProgress = (payload: boolean) =>
  ({ type: GET_MATERIALS_WARRANTY_PROGRESS, payload } as const);

export const clearWarrantyData = () => ({ type: CLEAR_WARRANTY_DATA } as const);

export const updateMaterialWarrantyItem = (payload: {
  materialId: string;
  quantity?: number;
  colorId?: string;
  colorName?: string;
  colorCode?: string;
}) => ({ type: UPDATE_MATERIAL_WARRANTY_ITEM, payload } as const);

export const actionMyJobs = {
  getMyJobsAsync,
  getMyJobsSuccess,
  getMyJobsFailed,
  getMyJobsProgress,
  getCommunitiesAsync,
  getCommunitiesSuccess,
  getCommunitiesFailed,
  getCommunitiesProgress,
  setMyJobFilterParams,
  resetMyJobState,
  getGanttDataAsync,
  getGanttDataSuccess,
  getGanttDataFailed,
  getGanttDataProgress,
  getMyJobsWarrantyAsync,
  getMyJobsWarrantySuccess,
  getMyJobsWarrantyFailed,
  getMyJobsWarrantyProgress,
  submitWarrantyAsync,
  submitWarrantySuccess,
  submitWarrantyFailed,
  submitWarrantyProgress,
  getMaterialsWarrantyAsync,
  getMaterialsWarrantySuccess,
  getMaterialsWarrantyFailed,
  getMaterialsWarrantyProgress,
  updateMaterialWarrantyItem,
  clearWarrantyData,
};

export type MyJobsAction = ReturnType<
  | typeof getMyJobsAsync
  | typeof getMyJobsSuccess
  | typeof getMyJobsFailed
  | typeof getMyJobsProgress
  | typeof getCommunitiesAsync
  | typeof getCommunitiesSuccess
  | typeof getCommunitiesFailed
  | typeof getCommunitiesProgress
  | typeof setMyJobFilterParams
  | typeof resetMyJobState
  | typeof getGanttDataAsync
  | typeof getGanttDataSuccess
  | typeof getGanttDataFailed
  | typeof getGanttDataProgress
  | typeof getMyJobsWarrantyAsync
  | typeof getMyJobsWarrantySuccess
  | typeof getMyJobsWarrantyFailed
  | typeof getMyJobsWarrantyProgress
  | typeof submitWarrantyAsync
  | typeof submitWarrantySuccess
  | typeof submitWarrantyFailed
  | typeof submitWarrantyProgress
  | typeof getMaterialsWarrantyAsync
  | typeof getMaterialsWarrantySuccess
  | typeof getMaterialsWarrantyFailed
  | typeof getMaterialsWarrantyProgress
  | typeof updateMaterialWarrantyItem
  | typeof clearWarrantyData
>;
