import {
  GET_MY_JOBS_SUCCESS,
  GET_MY_JOBS_FAILED,
  GET_MY_JOBS_PROGRESS,
  GET_COMMUNITIES_SUCCESS,
  GET_COMMUNITIES_FAILED,
  GET_COMMUNITIES_PROGRESS,
  SET_MY_JOB_FILTER_PARAMS,
  RESET_MY_JOB_STATE,
  GET_GANTT_DATA_SUCCESS,
  GET_GANTT_DATA_FAILED,
  GET_GANTT_DATA_PROGRESS,
  GET_MY_JOBS_WARRANTY_SUCCESS,
  GET_MY_JOBS_WARRANTY_FAILED,
  GET_MY_JOBS_WARRANTY_PROGRESS,
  SUBMIT_WARRANTY_SUCCESS,
  SUBMIT_WARRANTY_FAILED,
  SUBMIT_WARRANTY_PROGRESS,
  GET_MATERIALS_WARRANTY_SUCCESS,
  GET_MATERIALS_WARRANTY_FAILED,
  GET_MATERIALS_WARRANTY_PROGRESS,
  UPDATE_MATERIAL_WARRANTY_ITEM,
  CLEAR_WARRANTY_DATA,
} from './contants';
import { MyJobsAction } from './actions';
import { MyJobsState } from './types';

export const initialState: MyJobsState = {
  myJobs: {
    isLoading: false,
    error: null,
    data: [],
  },
  communities: {
    isLoading: false,
    error: null,
    data: [],
  },
  lastFilterParams: null,
  ganttData: {
    isLoading: false,
    error: null,
    data: {
      notStarted: [],
      inProgress: [],
      completed: [],
    },
  },
  myJobsWarranty: {
    isLoading: false,
    error: null,
    data: [],
  },
  submitWarranty: {
    isLoading: false,
    error: null,
    data: [],
  },
  materialsWarranty: {
    isLoading: false,
    error: null,
    data: [],
  },
};

export default function myJobReducer(
  state = initialState,
  action: MyJobsAction,
): MyJobsState {
  switch (action.type) {
    case GET_MY_JOBS_SUCCESS:
      return {
        ...state,
        myJobs: {
          isLoading: false,
          error: null,
          data: action.payload,
        },
      };
    case GET_MY_JOBS_FAILED:
      return {
        ...state,
        myJobs: {
          isLoading: false,
          error: action.payload,
          data: [],
        },
      };
    case GET_MY_JOBS_PROGRESS:
      return {
        ...state,
        myJobs: {
          ...state.myJobs,
          isLoading: action.payload,
        },
      };
    case GET_COMMUNITIES_SUCCESS:
      return {
        ...state,
        communities: {
          isLoading: false,
          error: null,
          data: action.payload,
        },
      };
    case GET_COMMUNITIES_FAILED:
      return {
        ...state,
        communities: {
          isLoading: false,
          error: action.payload,
          data: [],
        },
      };
    case GET_COMMUNITIES_PROGRESS:
      return {
        ...state,
        communities: {
          ...state.communities,
          isLoading: action.payload,
        },
      };
    case SET_MY_JOB_FILTER_PARAMS:
      return {
        ...state,
        lastFilterParams: action.payload,
      };
    case GET_GANTT_DATA_SUCCESS:
      return {
        ...state,
        ganttData: {
          isLoading: false,
          error: null,
          data: action.payload,
        },
      };
    case GET_GANTT_DATA_FAILED:
      return {
        ...state,
        ganttData: {
          isLoading: false,
          error: action.payload,
          data: {
            notStarted: [],
            inProgress: [],
            completed: [],
          },
        },
      };
    case GET_GANTT_DATA_PROGRESS:
      return {
        ...state,
        ganttData: {
          ...state.ganttData,
          isLoading: action.payload,
        },
      };
    case GET_MY_JOBS_WARRANTY_SUCCESS:
      return {
        ...state,
        myJobsWarranty: {
          isLoading: false,
          error: null,
          data: action.payload,
        },
      };
    case GET_MY_JOBS_WARRANTY_FAILED:
      return {
        ...state,
        myJobsWarranty: {
          isLoading: false,
          error: action.payload,
          data: [],
        },
      };
    case GET_MY_JOBS_WARRANTY_PROGRESS:
      return {
        ...state,
        myJobsWarranty: {
          ...state.myJobsWarranty,
          isLoading: action.payload,
        },
      };
    case SUBMIT_WARRANTY_SUCCESS:
      return {
        ...state,
        submitWarranty: {
          isLoading: false,
          error: null,
          data: action.payload,
        },
      };
    case SUBMIT_WARRANTY_FAILED:
      return {
        ...state,
        submitWarranty: {
          isLoading: false,
          error: action.payload,
          data: [],
        },
      };
    case SUBMIT_WARRANTY_PROGRESS:
      return {
        ...state,
        submitWarranty: {
          ...state.submitWarranty,
          isLoading: action.payload,
        },
      };
    case GET_MATERIALS_WARRANTY_SUCCESS:
      return {
        ...state,
        materialsWarranty: {
          isLoading: false,
          error: null,
          data: action.payload,
        },
      };
    case GET_MATERIALS_WARRANTY_FAILED:
      return {
        ...state,
        materialsWarranty: {
          isLoading: false,
          error: action.payload,
          data: [],
        },
      };
    case GET_MATERIALS_WARRANTY_PROGRESS:
      return {
        ...state,
        materialsWarranty: {
          ...state.materialsWarranty,
          isLoading: action.payload,
        },
      };
    case UPDATE_MATERIAL_WARRANTY_ITEM:
      return {
        ...state,
        materialsWarranty: {
          ...state.materialsWarranty,
          data: (state.materialsWarranty.data as any[]).map((item: any) =>
            item.materialId === action.payload.materialId
              ? { ...item, ...action.payload }
              : item,
          ),
        },
      };
    case CLEAR_WARRANTY_DATA:
      return {
        ...state,
        materialsWarranty: {
          isLoading: false,
          error: null,
          data: [],
        },
      };
    case RESET_MY_JOB_STATE:
      return initialState;
    default:
      return state;
  }
}
