import { all, call, put, takeEvery } from 'redux-saga/effects';
import {
  GET_MY_JOBS_ASYNC,
  GET_MY_JOBS_FAILED,
  GET_MY_JOBS_PROGRESS,
  GET_MY_JOBS_SUCCESS,
  GET_COMMUNITIES_ASYNC,
  GET_COMMUNITIES_FAILED,
  GET_COMMUNITIES_PROGRESS,
  GET_COMMUNITIES_SUCCESS,
  GET_GANTT_DATA_PROGRESS,
  GET_GANTT_DATA_FAILED,
  GET_GANTT_DATA_SUCCESS,
  GET_GANTT_DATA_ASYNC,
  GET_MY_JOBS_WARRANTY_PROGRESS,
  GET_MY_JOBS_WARRANTY_FAILED,
  GET_MY_JOBS_WARRANTY_SUCCESS,
  GET_MY_JOBS_WARRANTY_ASYNC,
  SUBMIT_WARRANTY_PROGRESS,
  SUBMIT_WARRANTY_FAILED,
  SUBMIT_WARRANTY_SUCCESS,
  SUBMIT_WARRANTY_ASYNC,
  GET_MATERIALS_WARRANTY_PROGRESS,
  GET_MATERIALS_WARRANTY_FAILED,
  GET_MATERIALS_WARRANTY_SUCCESS,
  GET_MATERIALS_WARRANTY_ASYNC,
} from './contants';
import {
  fetchMyJobs,
  fetchCommunities,
  fetchWarrantyDetailData,
  fetchMaterialWarranty,
  fetchSubmitWarranty,
} from '../../../api/myjob';
import { ResponseApi } from '../../store/types';
import {
  HIDE_LOADING_OVERLAY,
  SHOW_ALERT,
  SHOW_LOADING_OVERLAY,
} from '../app/constants';
import i18n from '../../../i18n';

const getMyJobs = function* (action: any): Generator<any, void, any> {
  try {
    yield put({ type: GET_MY_JOBS_PROGRESS, payload: true });
    yield put({ type: SHOW_LOADING_OVERLAY });
    const response = (yield call(fetchMyJobs, action.payload)) as ResponseApi;
    if (response.status !== 200) {
      yield put({ type: GET_MY_JOBS_FAILED, payload: response.message });
      return;
    }

    // Map response data to JobItem array
    const items = response.data?.items || [];

    yield put({
      type: GET_MY_JOBS_SUCCESS,
      payload: items,
    });
  } catch (error) {
    yield put({ type: GET_MY_JOBS_FAILED, payload: error });
  } finally {
    yield put({ type: GET_MY_JOBS_PROGRESS, payload: false });
    yield put({ type: HIDE_LOADING_OVERLAY });
  }
};

const getCommunities = function* (): Generator<any, void, any> {
  try {
    yield put({ type: GET_COMMUNITIES_PROGRESS, payload: true });
    const response = (yield call(fetchCommunities)) as ResponseApi;
    if (response.status !== 200) {
      yield put({ type: GET_COMMUNITIES_FAILED, payload: response.message });
      return;
    }
    yield put({ type: GET_COMMUNITIES_SUCCESS, payload: response.data });
  } catch (error) {
    yield put({ type: GET_COMMUNITIES_FAILED, payload: error });
  } finally {
    yield put({ type: GET_COMMUNITIES_PROGRESS, payload: false });
  }
};

const getGanttData = function* (action: any): Generator<any, void, any> {
  try {
    yield put({ type: GET_GANTT_DATA_PROGRESS, payload: true });
    yield put({ type: SHOW_LOADING_OVERLAY });

    // action.payload is an array of params (one per status tab)
    // Order: [NOT_STARTED, IN_PROGRESS, COMPLETED]
    const paramsList: any[] = action.payload;

    // Call all APIs in parallel
    const responses: ResponseApi[] = yield all(
      paramsList.map((params: any) => call(fetchMyJobs, params)),
    );

    // Build object with 3 child arrays by status
    const ganttDataByStatus = {
      notStarted:
        responses[0]?.status === 200 ? responses[0]?.data?.items || [] : [],
      inProgress:
        responses[1]?.status === 200 ? responses[1]?.data?.items || [] : [],
      completed:
        responses[2]?.status === 200 ? responses[2]?.data?.items || [] : [],
    };

    yield put({ type: GET_GANTT_DATA_SUCCESS, payload: ganttDataByStatus });
  } catch (error) {
    yield put({ type: GET_GANTT_DATA_FAILED, payload: error });
  } finally {
    yield put({ type: GET_GANTT_DATA_PROGRESS, payload: false });
    yield put({ type: HIDE_LOADING_OVERLAY });
  }
};

const getMyJobsWarranty = function* (action: any): Generator<any, void, any> {
  try {
    yield put({ type: GET_MY_JOBS_WARRANTY_PROGRESS, payload: true });
    yield put({ type: SHOW_LOADING_OVERLAY });
    const response = (yield call(
      fetchWarrantyDetailData,
      action.payload,
    )) as ResponseApi;
    if (response.status !== 200) {
      yield put({
        type: GET_MY_JOBS_WARRANTY_FAILED,
        payload: response.message,
      });
      return;
    }

    yield put({
      type: GET_MY_JOBS_WARRANTY_SUCCESS,
      payload: response?.data,
    });
  } catch (error) {
    yield put({ type: GET_MY_JOBS_WARRANTY_FAILED, payload: error });
  } finally {
    yield put({ type: GET_MY_JOBS_WARRANTY_PROGRESS, payload: false });
    yield put({ type: HIDE_LOADING_OVERLAY });
  }
};

const submitWarranty = function* (action: any): Generator<any, void, any> {
  try {
    yield put({ type: SUBMIT_WARRANTY_PROGRESS, payload: true });
    yield put({ type: SHOW_LOADING_OVERLAY });
    const { goBack, ...apiPayload } = action?.payload || {};

    const response = (yield call(
      fetchSubmitWarranty,
      apiPayload,
    )) as ResponseApi;
    if (response.status !== 200) {
      yield put({
        type: SHOW_ALERT,
        payload: { message: response.message, type: 'error' },
      });
      yield put({
        type: SUBMIT_WARRANTY_FAILED,
        payload: response.message || i18n.t('WARRANTY_SUBMITTED_FAILED'),
      });
      return;
    }

    yield put({
      type: SUBMIT_WARRANTY_SUCCESS,
      payload: response?.data,
    });
    yield put({
      type: SHOW_ALERT,
      payload: {
        message: response.message || i18n.t('WARRANTY_SUBMITTED_SUCCESSFULLY'),
        type: 'success',
        onClose: () => {
          action?.payload?.goBack();
        },
      },
    });
  } catch (error) {
    yield put({ type: SUBMIT_WARRANTY_FAILED, payload: error });
    yield put({
      type: SUBMIT_WARRANTY_FAILED,
      payload: i18n.t('WARRANTY_SUBMITTED_FAILED'),
    });
  } finally {
    yield put({ type: SUBMIT_WARRANTY_PROGRESS, payload: false });
    yield put({ type: HIDE_LOADING_OVERLAY });
  }
};

const getMaterialsWarranty = function* (
  action: any,
): Generator<any, void, any> {
  try {
    yield put({ type: GET_MATERIALS_WARRANTY_PROGRESS, payload: true });
    yield put({ type: SHOW_LOADING_OVERLAY });

    const response = (yield call(
      fetchMaterialWarranty,
      action.payload,
    )) as ResponseApi;
    if (response.status !== 200) {
      yield put({
        type: GET_MATERIALS_WARRANTY_FAILED,
        payload: response.message,
      });
      return;
    }

    yield put({
      type: GET_MATERIALS_WARRANTY_SUCCESS,
      payload: response?.data,
    });
  } catch (error) {
    yield put({ type: GET_MATERIALS_WARRANTY_FAILED, payload: error });
  } finally {
    yield put({ type: GET_MATERIALS_WARRANTY_PROGRESS, payload: false });
    yield put({ type: HIDE_LOADING_OVERLAY });
  }
};

export default function* myJobSaga() {
  yield takeEvery(GET_MY_JOBS_ASYNC, getMyJobs);
  yield takeEvery(GET_COMMUNITIES_ASYNC, getCommunities);
  yield takeEvery(GET_GANTT_DATA_ASYNC, getGanttData);
  yield takeEvery(GET_MY_JOBS_WARRANTY_ASYNC, getMyJobsWarranty);
  yield takeEvery(SUBMIT_WARRANTY_ASYNC, submitWarranty);
  yield takeEvery(GET_MATERIALS_WARRANTY_ASYNC, getMaterialsWarranty);
}
